INSERT INTO Consensus (
  consensus_statement, topic, version, agreement_level,
  num_supporting_papers, num_contradicting_papers, notes
) VALUES (
  'Chronic SCI lesion architecture is a multicompartment structure, not a single scar. The core evidence supports separately queryable fibrotic or ECM-rich matrix, astrocytic border, immune/myeloid containment zone, spared or reactive neural tissue, altered white matter, and cystic or repaired-tissue cavities when present.',
  'M1B-T001: Core lesion architecture',
  1,
  'moderate',
  NULL,
  NULL,
  '{"boundary_or_contradiction_handling": "Compartment definitions vary by model, time point, assay resolution, and whether lesions are contusive, hemisection, cavitary, or scaffold-repaired; do not collapse all scar biology into one field.", "boundary_tracker_ids": [], "claim_tracker_ids": ["M1B-C019", "M1B-C020", "M1B-C021", "M1B-C022", "M1B-C023", "M1B-C024"], "consensus_draft_id": "M1B-S001", "materialization_note": "Consensus-only compatibility export; full materialization with Consensus_Observation rows is generated by scripts/export_module1_full_sql.py.", "observation_tracker_ids": ["M1B-O037", "M1B-O038", "M1B-O039", "M1B-O040", "M1B-O041", "M1B-O042", "M1B-O043", "M1B-O044", "M1B-O045", "M1B-O046"], "source_agreement_label": "moderate", "source_tracker": "modules/Module_1B_TRACKER.md", "supporting_evidence_scope": "Supported by spatial transcriptomics and scar-matrix full-text evidence, with lower-confidence abstract/source-page support for chronic zone architecture and single-cell lesion ecology; observations M1B-O037-M1B-O046; claims M1B-C019-M1B-C024.", "topic_id": "M1B-T001"}'
);

INSERT INTO Consensus (
  consensus_statement, topic, version, agreement_level,
  num_supporting_papers, num_contradicting_papers, notes
) VALUES (
  'SCI fibrotic scarring arises from perivascular and meningeal-associated stromal lineages, but lineage assignment depends on marker system, Cre driver, injury geometry, dural disruption, and endpoint. The consensus is modulation, not ablation: partial attenuation can support repair in some models, whereas loss of closure-producing stroma can be harmful.',
  'M1B-T002: Fibrotic scar cellular origins',
  1,
  'moderate',
  NULL,
  NULL,
  '{"boundary_or_contradiction_handling": "M1B-X002 resolves apparent pericyte-versus-fibroblast conflicts as marker/system dependent; store marker, lineage driver, injury model, and dural status with each claim.", "boundary_tracker_ids": ["M1B-X002"], "claim_tracker_ids": ["M1B-C006", "M1B-C007", "M1B-C008", "M1B-C009", "M1B-C010", "M1B-C011", "M1B-C012"], "consensus_draft_id": "M1B-S002", "materialization_note": "Consensus-only compatibility export; full materialization with Consensus_Observation rows is generated by scripts/export_module1_full_sql.py.", "observation_tracker_ids": ["M1B-O012", "M1B-O013", "M1B-O014", "M1B-O015", "M1B-O016", "M1B-O017", "M1B-O018", "M1B-O019", "M1B-O020", "M1B-O021", "M1B-O022", "M1B-O023", "M1B-O024", "M1B-O025", "M1B-O026"], "source_agreement_label": "moderate", "source_tracker": "modules/Module_1B_TRACKER.md", "supporting_evidence_scope": "Supported by three full-text lineage/function studies; observations M1B-O012-M1B-O026; claims M1B-C006-M1B-C012.", "topic_id": "M1B-T002"}'
);

INSERT INTO Consensus (
  consensus_statement, topic, version, agreement_level,
  num_supporting_papers, num_contradicting_papers, notes
) VALUES (
  'Astrocytic scar borders are active wound-repair and containment structures with separable programs for formation, maintenance, recruitment, and morphology. Established scar-forming astrocytes may resist direct reversal, while border recruitment and organization remain intervention-sensitive in vivo.',
  'M1B-T003: Astrocytic border and wound-repair state',
  1,
  'moderate',
  NULL,
  NULL,
  '{"boundary_or_contradiction_handling": "M1B-X003 distinguishes established astrocyte-state reversal from border recruitment/organization. Source-page studies should remain medium confidence until full-text upgrades.", "boundary_tracker_ids": ["M1B-X003"], "claim_tracker_ids": ["M1B-C013", "M1B-C014", "M1B-C015", "M1B-C016", "M1B-C017", "M1B-C018"], "consensus_draft_id": "M1B-S003", "materialization_note": "Consensus-only compatibility export; full materialization with Consensus_Observation rows is generated by scripts/export_module1_full_sql.py.", "observation_tracker_ids": ["M1B-O027", "M1B-O028", "M1B-O029", "M1B-O030", "M1B-O031", "M1B-O032", "M1B-O033", "M1B-O034", "M1B-O035", "M1B-O036"], "source_agreement_label": "moderate", "source_tracker": "modules/Module_1B_TRACKER.md", "supporting_evidence_scope": "Strongest support comes from Tamaru 2023 full text, with source-page support from immune-corralling, Ryk, and wound-repair astrocyte studies; observations M1B-O027-M1B-O036; claims M1B-C013-M1B-C018.", "topic_id": "M1B-T003"}'
);

INSERT INTO Consensus (
  consensus_statement, topic, version, agreement_level,
  num_supporting_papers, num_contradicting_papers, notes
) VALUES (
  'Chronic SCI changes lesion mechanics, but stiffness direction is model- and method-dependent. No universal chronic-scar stiffness claim should be encoded without species, injury model, time point, tissue preparation, AFM method, and lesion subregion.',
