INSERT INTO Consensus (
  consensus_statement, topic, version, agreement_level,
  num_supporting_papers, num_contradicting_papers, notes
) VALUES (
  'Chronic scar resection divides into distinct intervention classes: tissue removal alone and resection followed by cavity or gap reconstruction. Resection alone is not consensus-reparative and may be harmful in contusion models, whereas scaffold or cell filling is a recurring but model- and endpoint-dependent reconstruction strategy.',
  'M1B-T005: Cavitary lesions, scar resection, and scaffold filling',
  1,
  'moderate',
  NULL,
  NULL,
  '{"boundary_or_contradiction_handling": "M1B-X004 resolves the apparent conflict by distinguishing tissue removal from reconstruction after resection; efficacy claims should not be generalized beyond feasibility/safety or specific animal endpoints.", "boundary_tracker_ids": ["M1B-X004"], "claim_tracker_ids": ["M1B-C030", "M1B-C031", "M1B-C032", "M1B-C033", "M1B-C034"], "consensus_draft_id": "M1B-S005", "materialization_note": "Consensus-only compatibility export; full materialization with Consensus_Observation rows is generated by scripts/export_module1_full_sql.py.", "observation_tracker_ids": ["M1B-O056", "M1B-O057", "M1B-O058", "M1B-O059", "M1B-O060", "M1B-O061", "M1B-O062"], "source_agreement_label": "moderate", "source_tracker": "modules/Module_1B_TRACKER.md", "supporting_evidence_scope": "Supported by two full-text resection/human scaffold studies plus abstract/source-page scaffold support; observations M1B-O056-M1B-O062; claims M1B-C030-M1B-C034.", "topic_id": "M1B-T005"}'
);

INSERT INTO Consensus (
  consensus_statement, topic, version, agreement_level,
  num_supporting_papers, num_contradicting_papers, notes
) VALUES (
  'Spared and lesion-remote white matter is an active recovery-linked compartment rather than normal residual tissue. It can carry chronic degeneration, repair-associated glial and immune remodeling, MRI-visible tract changes, debris and lipid-handling programs, and behavioral associations.',
  'M1B-T006: Spared and remote white matter',
  1,
  'moderate',
  NULL,
  NULL,
